inputs.where:
@And(
  equals(
    item()?['_hso_projectproductid_value'],
    items('Apply_to_each_created_Project_Product')?['GUIDold']
  ),
  not(
    equals(
      item()?['hso_isbillofmaterial'],
      true
    )
  )
)

Calculate_Batch_Size.inputs:
@add(
  div(
    length(body('Filter_Payload_by_Level')), 
    outputs('Calculate_Parallelism')
  ), 
  if(
    greaterOrEquals(
      mod(
        length(body('Filter_Payload_by_Level')),
        outputs('Calculate_Parallelism')
      ),
      1
    ), 
    1, 
    0
  )
)

select.Message:
@coalesce(
  item()?['outputs']?['body']?['error']?['message'],
  item()?['outputs']?['body']?['message'],
  item()?['error']?['message'],
  'No Message found. Please check Flow-Run.'
)
